def max_thieves_caught(arr, k):
    n = len(arr)
    policemen_indices = []
    thieves_indices = []

    for i in range(n):
        if arr[i] == 'P':
            policemen_indices.append(i)
        elif arr[i] == 'T':
            thieves_indices.append(i)

    caught_thieves = 0
    p_ptr = 0
    t_ptr = 0

    while p_ptr < len(policemen_indices) and t_ptr < len(thieves_indices):
        policeman_pos = policemen_indices[p_ptr]
        thief_pos = thieves_indices[t_ptr]

        if abs(policeman_pos - thief_pos) <= k:
            caught_thieves += 1
            p_ptr += 1
            t_ptr += 1
        elif thief_pos < policeman_pos:
            t_ptr += 1
        else:
            p_ptr += 1

    return caught_thieves
